import{c as t,Q as n,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"Agent Harness for Large Language Model Agents: A Survey","description":"","frontmatter":{"title":"Agent Harness for Large Language Model Agents: A Survey","authors":"Qianyu Meng, Yanan Wang, Liyi Chen, Qimeng Wang, Chengqiang Lu, Wei Wu, Yan Gao, Yi Wu, Yao Hu","published":"2026-04-07T00:00:00.000Z","source":"https://www.preprints.org/manuscript/202604.0428/v1"},"headers":[],"relativePath":"research/agent-harness/references/2026-04-07-agent-harness-survey.md","filePath":"research/agent-harness/references/2026-04-07-agent-harness-survey.md","lastUpdated":1779901665000}'),i={name:"research/agent-harness/references/2026-04-07-agent-harness-survey.md"};function s(o,e,l,c,d,g){return n(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="agent-harness-for-large-language-model-agents-a-survey" tabindex="-1">Agent Harness for Large Language Model Agents: A Survey <a class="header-anchor" href="#agent-harness-for-large-language-model-agents-a-survey" aria-label="Permalink to &quot;Agent Harness for Large Language Model Agents: A Survey&quot;">​</a></h1><p><strong>Authors</strong>: Qianyu Meng, Yanan Wang, Liyi Chen, Qimeng Wang, Chengqiang Lu, Wei Wu, Yan Gao, Yi Wu, Yao Hu<br><strong>Published</strong>: April 7, 2026 (Posted); April 3, 2026 (Submitted)<br><strong>Source</strong>: <a href="https://www.preprints.org/manuscript/202604.0428/v1" target="_blank" rel="noreferrer">https://www.preprints.org/manuscript/202604.0428/v1</a><br><strong>DOI</strong>: 10.20944/preprints202604.0428.v1<br><strong>Status</strong>: Preprint (not peer-reviewed)</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The survey addresses how agent execution infrastructure—rather than underlying model capabilities—determines reliability in deployed LLM systems. The authors argue that &quot;harness-level changes alone...produce gains of up to 10× on coding benchmarks&quot; without model modification. They introduce a formal six-component framework H=(E,T,C,S,L,V) encompassing execution loops, tool integration, context management, state persistence, lifecycle governance, and evaluation interfaces. The work analyzes 22 systems, identifies 9 cross-cutting challenges, and grounds claims in empirical studies including HAL, SWE-bench, and AgencyBench.</p><hr><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>The paper challenges the prevailing assumption that &quot;agent capability is primarily a function of model capability.&quot; Empirical evidence increasingly shows that infrastructure design, not model quality alone, emerges as &quot;the binding constraint for real-world agent system reliability.&quot;</p><p>The authors identify a <strong>practitioner-research gap</strong>: practitioners empirically know harness infrastructure matters but lack formal vocabulary to systematize improvements; researchers have detailed component-level models but lack cross-cutting infrastructure views explaining how component quality translates into system reliability. This survey bridges that gap.</p><hr><h2 id="formal-framework-h-e-t-c-s-l-v" tabindex="-1">Formal Framework: H = (E, T, C, S, L, V) <a class="header-anchor" href="#formal-framework-h-e-t-c-s-l-v" aria-label="Permalink to &quot;Formal Framework: H = (E, T, C, S, L, V)&quot;">​</a></h2><p>The paper proposes a six-component harness framework:</p><table tabindex="0"><thead><tr><th>Component</th><th>Label</th><th>Description</th></tr></thead><tbody><tr><td><strong>E</strong></td><td>Execution loop</td><td>Observe-think-act cycle management</td></tr><tr><td><strong>T</strong></td><td>Tool registry</td><td>Typed, validated tool interfaces</td></tr><tr><td><strong>C</strong></td><td>Context manager</td><td>Information control into model</td></tr><tr><td><strong>S</strong></td><td>State store</td><td>Cross-turn persistence</td></tr><tr><td><strong>L</strong></td><td>Lifecycle hooks</td><td>Authentication, policy enforcement</td></tr><tr><td><strong>V</strong></td><td>Evaluation interface</td><td>Standardized trajectory capture</td></tr></tbody></table><p>Each component is formally specified and analyzed for how it contributes to system reliability independent of the underlying model&#39;s capabilities.</p><hr><h2 id="empirical-evidence" tabindex="-1">Empirical Evidence <a class="header-anchor" href="#empirical-evidence" aria-label="Permalink to &quot;Empirical Evidence&quot;">​</a></h2><p>The survey cites converging findings showing harness-level changes alone produce substantial gains:</p><ul><li><strong>Up to 10× on coding benchmarks</strong> without model modification</li><li><strong>+26% on TerminalBench</strong> from infrastructure changes</li><li><strong>+4.7 percentage points on mathematical reasoning</strong> through harness configuration</li></ul><p><strong>Peer-reviewed sources</strong>:</p><ul><li>HAL (Kapoor et al.): standardized evaluation infrastructure reducing implementation time from &quot;weeks to hours&quot; while eliminating common implementation bugs</li><li>OSWorld: execution environment standardization enabling reproducible multi-modal agent benchmarking</li><li>SWE-bench: reproducible coding task evaluation demonstrating the role of environment consistency</li></ul><p><strong>Preprint-tier sources</strong> (requiring peer-review confirmation):</p><ul><li>AgencyBench</li><li>SkillsBench</li><li>SandboxEscapeBench</li></ul><p><strong>Practitioner reports</strong>: OpenAI, Stripe, and METR corroborate the binding constraint thesis illustratively rather than providing definitive proof.</p><hr><h2 id="historical-account-three-lineages" tabindex="-1">Historical Account: Three Lineages <a class="header-anchor" href="#historical-account-three-lineages" aria-label="Permalink to &quot;Historical Account: Three Lineages&quot;">​</a></h2><p>The harness concept evolved from three distinct traditions:</p><ol><li><strong>Software test harnesses</strong> — governance templates and execution scaffolding originally designed to isolate components under test; the structural metaphor of &quot;harness&quot; as controlling infrastructure derives from this tradition</li><li><strong>Reinforcement learning environments</strong> — interface standards (e.g., OpenAI Gym) establishing the observe-act loop as a formal abstraction and providing reproducible agent-environment interaction patterns</li><li><strong>Early LLM frameworks</strong> — failure mode catalogs emerging from early deployment experiences (LangChain, AutoGPT-era systems), identifying where unstructured execution leads to reliability collapse</li></ol><hr><h2 id="system-taxonomy-22-representative-systems" tabindex="-1">System Taxonomy: 22 Representative Systems <a class="header-anchor" href="#system-taxonomy-22-representative-systems" aria-label="Permalink to &quot;System Taxonomy: 22 Representative Systems&quot;">​</a></h2><p>The survey analyzes 22 systems against the H=(E,T,C,S,L,V) completeness matrix, revealing which components each system implements and where gaps persist. The analysis shows:</p><ul><li>Most systems implement <strong>E</strong> (execution loop) and <strong>T</strong> (tool registry) comprehensively</li><li><strong>V</strong> (evaluation interface) is the most consistently under-implemented component</li><li><strong>S</strong> (state store) and <strong>L</strong> (lifecycle hooks) show high variance across systems</li><li>Systems with higher completeness scores correlate with better benchmark reliability, not necessarily better underlying models</li></ul><p>The completeness matrix functions as both a diagnostic tool and a design checklist for new agent systems.</p><hr><h2 id="nine-cross-cutting-challenges" tabindex="-1">Nine Cross-Cutting Challenges <a class="header-anchor" href="#nine-cross-cutting-challenges" aria-label="Permalink to &quot;Nine Cross-Cutting Challenges&quot;">​</a></h2><p>The survey identifies nine technical challenges where infrastructure remains underdeveloped relative to component capabilities:</p><ol><li><strong>Context window saturation</strong>: accumulation of tool call history and intermediate results degrades model focus; no standardized pruning strategies exist</li><li><strong>Tool call validation</strong>: typed interfaces reduce but do not eliminate invalid tool invocations; schema-level validation remains inconsistent across frameworks</li><li><strong>State persistence across interruptions</strong>: long-running agents lack reliable checkpointing; session failures require full restarts rather than resumption</li><li><strong>Evaluation trajectory standardization</strong>: incompatible logging formats prevent cross-system comparisons; the field lacks a universal trace format</li><li><strong>Lifecycle policy enforcement</strong>: authentication, rate limiting, and safety checks are bolt-on additions rather than first-class harness primitives</li><li><strong>Multi-agent coordination protocols</strong>: sub-agent dispatch and result aggregation lack standardized interfaces; each framework invents its own conventions</li><li><strong>Sandboxing and isolation</strong>: execution environments vary from full VMs to process-level isolation; security guarantees are difficult to reason about across configurations</li><li><strong>Harness-model coupling</strong>: models post-trained on specific harnesses show degraded performance when transferred; coupling is opaque and difficult to measure</li><li><strong>Observability gaps</strong>: intermediate reasoning steps and context window contents are largely invisible to operators, making debugging difficult</li></ol><hr><h2 id="scope-and-limitations" tabindex="-1">Scope and Limitations <a class="header-anchor" href="#scope-and-limitations" aria-label="Permalink to &quot;Scope and Limitations&quot;">​</a></h2><ul><li>Focuses on end-to-end agentic systems; excludes single-step language model use</li><li>Analyzes only systems with public documentation; proprietary harness designs remain unstudied</li><li>Framework validation through factor analysis and predictive testing is identified as future work</li><li>Preprint status means findings have not undergone peer review</li></ul><hr><h2 id="significance" tabindex="-1">Significance <a class="header-anchor" href="#significance" aria-label="Permalink to &quot;Significance&quot;">​</a></h2><p>This survey provides the first formal vocabulary for the infrastructure layer that practitioners have been building empirically. The H=(E,T,C,S,L,V) framework enables:</p><ul><li>Systematic diagnosis of agent reliability failures by component</li><li>Cross-system comparison using a common completeness matrix</li><li>Research agenda identification through the nine challenge taxonomy</li><li>Design guidance for new agent systems prioritizing harness completeness over model capability</li></ul><p>The authors argue that the field&#39;s focus on model benchmarks (MMLU, HumanEval) systematically underweights the infrastructure variable. Two systems running the same model can show dramatically different real-world reliability based solely on harness design.</p><hr><h2 id="key-quotes" tabindex="-1">Key Quotes <a class="header-anchor" href="#key-quotes" aria-label="Permalink to &quot;Key Quotes&quot;">​</a></h2><blockquote><p>&quot;Infrastructure design, not model quality alone, emerges as the binding constraint for real-world agent system reliability.&quot;</p></blockquote><blockquote><p>&quot;Harness-level changes alone produce gains of up to 10× on coding benchmarks without model modification.&quot;</p></blockquote><blockquote><p>&quot;Practitioners empirically know harness infrastructure matters but lack formal vocabulary to systematize improvements.&quot;</p></blockquote>',49)])])}const m=t(i,[["render",s]]);export{h as __pageData,m as default};
